B.KO=new A.bV("gen_pc_5","economic_law","\uacfc\uc9d5\uae08","\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uacfc\uc9d5\uae08 \uc0b0\uc815 \uc2dc \uace0\ub824\ud558\ub294 \uc694\uc18c\ub85c \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\uc740 \uac83\uc740?",B.DI,4,'\uacf5\uc815\uac70\ub798\ubc95\uc0c1 \uacfc\uc9d5\uae08\uc744 \ubd80\uacfc\ud560 \ub54c \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uace0\ub824\ud558\ub294 \uc694\uc18c\ub294 \uc704\ubc18\ud589\uc704\uc758 \ub0b4\uc6a9\xb7\uc815\ub3c4, \uae30\uac04\xb7\ud69f\uc218, \uc704\ubc18\ud589\uc704\ub85c \ucde8\ub4dd\ud55c \uc774\uc775\uc758 \uaddc\ubaa8 \ub4f1\uc774\uba70, \uc774\ub294 \uc704\ubc18\ud589\uc704\uc758 \uc911\ub300\uc131\uacfc \ubd80\ub2f9\uc774\ub4dd\uc758 \uaddc\ubaa8\uc5d0 \ube44\ub840\ud558\uc5ec \uc81c\uc7ac \uc218\uc900\uc744 \uc815\ud558\uae30 \uc704\ud55c \uac83\uc774\ub2e4. \ubc18\uba74 "\uc704\ubc18\uc0ac\uc5c5\uc790\uc758 \uc784\uc9c1\uc6d0 \uc218"\ub294 \uacfc\uc9d5\uae08 \uc0b0\uc815\uc758 \ubc95\uc815 \uace0\ub824\uc694\uc18c\ub85c \uba85\uc2dc\ub418\uc5b4 \uc788\uc9c0 \uc54a\ub2e4 \u2014 \uacfc\uc9d5\uae08\uc740 \uc5b4\ub514\uae4c\uc9c0\ub098 \uc704\ubc18\ud589\uc704 \uc790\uccb4\uc758 \uacbd\uc911\uacfc \uadf8\ub85c \uc778\ud55c \uc774\ub4dd \uaddc\ubaa8\ub97c \uae30\uc900\uc73c\ub85c \uc0b0\uc815\ub418\ub294 \uac83\uc774\uc9c0, \uae30\uc5c5\uc758 \uc870\uc9c1 \uaddc\ubaa8(\uc784\uc9c1\uc6d0 \uc218)\ub97c \uc9c1\uc811\uc801\uc778 \uc0b0\uc815 \uae30\uc900\uc73c\ub85c \uc0bc\uc9c0 \uc54a\ub294\ub2e4.',B.Gm,B.E6,null)
B.Es=s(["\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uacc4\uc57d\uc5d0\uc11c \uc815\ud55c \uac83\ubcf4\ub2e4 \ub0ae\uc740 \ub300\uae08\uc744 \uc77c\ubc29\uc801\uc73c\ub85c \uc9c0\uae09\ud558\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uc790\uae30 \uc0c1\ud488\uacfc \ud568\uaed8 \ub2e4\ub978 \uc0c1\ud488\uc758 \uad6c\uc785\uc744 \uac15\uc81c\ud558\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uc790\uae30 \ub610\ub294 \uacc4\uc5f4\ud68c\uc0ac\uac00 \uc9c0\uc815\ud558\ub294 \uc0ac\uc5c5\uc790\uc758 \uc0c1\ud488\uc744 \uad6c\uc785\ud558\ub3c4\ub85d \uac15\uc694\ud558\ub294 \ud589\uc704","\uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uc2e0\uaddc \uacbd\uc7c1\uc0ac\uc5c5\uc790\uc640 \uac70\ub798\ud558\uc9c0 \ubabb\ud558\ub3c4\ub85d \ubc30\ud0c0\uc870\uac74\uc744 \ubd99\uc774\ub294 \ud589\uc704","\uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \ud2b9\uc815 \ud310\ub9e4\ubaa9\ud45c\ub97c \uc81c\uc2dc\ud558\uace0 \ubbf8\ub2ec\uc131 \uc2dc \uacc4\uc57d\uc744 \ud574\uc9c0\ud558\ub294 \ud589\uc704"],t.s)
