B.KM=new A.bV("gen_ub_4","economic_law","\uac70\ub798\uc0c1\uc9c0\uc704\ub0a8\uc6a9",'\ub3c5\uc810\uaddc\uc81c \ubc0f \uacf5\uc815\uac70\ub798\uc5d0 \uad00\ud55c \ubc95\ub960\uc0c1 \uac70\ub798\uc0c1 \uc9c0\uc704\ub0a8\uc6a9 \ud589\uc704 \uc911 "\ubd88\uc774\uc775\uc81c\uacf5"\uc5d0 \ud574\ub2f9\ud558\ub294 \uc0ac\ub840\ub85c \uac00\uc7a5 \uc801\uc808\ud55c \uac83\uc740?',B.Es,0,'"\ubd88\uc774\uc775\uc81c\uacf5"\uc740 \uad6c\uc785\uac15\uc81c\xb7\uc774\uc775\uc81c\uacf5\uac15\uc694\xb7\ud310\ub9e4\ubaa9\ud45c\uac15\uc81c\ucc98\ub7fc \ubcc4\ub3c4\ub85c \uc720\ud615\ud654\ub41c \ud589\uc704 \uc678\uc758 \ubc29\ubc95\uc73c\ub85c, \uac70\ub798\uc0c1\ub300\ubc29\uc5d0\uac8c \uc77c\ubc29\uc801\uc73c\ub85c \ubd88\uc774\uc775\uc774 \ub418\ub294 \uae09\ubd80\xb7\ub300\uac00\ub97c \uc815\ud558\uac70\ub098 \uacc4\uc57d \ub0b4\uc6a9\uc744 \ubd88\ub9ac\ud558\uac8c \ubcc0\uacbd\ud558\ub294 \ud589\uc704\ub97c \ud3ec\uad04\uc801\uc73c\ub85c \uaddc\uc81c\ud558\ub294 \uc720\ud615\uc774\ub2e4. \uc815\ub2f9\ud55c \uc774\uc720 \uc5c6\uc774 \uacc4\uc57d\uc5d0\uc11c \uc815\ud55c \ub300\uae08\ubcf4\ub2e4 \ub0ae\uc740 \uae08\uc561\uc744 \uc77c\ubc29\uc801\uc73c\ub85c \uc9c0\uae09\ud558\ub294 \ud589\uc704\ub294 \ub300\ud45c\uc801\uc778 \ubd88\uc774\uc775\uc81c\uacf5 \uc0ac\ub840\uc5d0 \ud574\ub2f9\ud55c\ub2e4. \ubc18\uba74 \u2461\ub294 \ub07c\uc6cc\ud314\uae30(\uac70\ub798\uac15\uc81c), \u2462\uc740 \uad6c\uc785\uac15\uc81c, \u2463\ub294 \ubc30\ud0c0\uc870\uac74\ubd80\uac70\ub798(\uad6c\uc18d\uc870\uac74\ubd80\uac70\ub798), \u2464\ub294 \ud310\ub9e4\ubaa9\ud45c\uac15\uc81c\ub85c\uc11c \uac01\uac01 \ubcc4\ub3c4\uc758 \ud558\uc704\uc720\ud615\uc774\ubbc0\ub85c \uc11c\ub85c \ud63c\ub3d9\ud558\uc9c0 \uc54a\uc544\uc57c \ud55c\ub2e4.',B.ET,B.Gg,null)
B.F2=s(["\ub458 \uc774\uc0c1\uc758 \uc0ac\uc5c5\uc790 \uac04\uc758 \ud569\uc758\uac00 \uc788\uc5b4\uc57c \ud55c\ub2e4","\ud569\uc758\ub294 \uba85\uc2dc\uc801 \ud569\uc758\ubfd0\ub9cc \uc544\ub2c8\ub77c \ubb35\uc2dc\uc801 \uc758\uc0ac\uc5f0\ub77d\uc73c\ub85c\ub3c4 \uc778\uc815\ub420 \uc218 \uc788\ub2e4","\ud569\uc758\uc758 \uc874\uc7ac\ub294 \uc774\ub97c \uc8fc\uc7a5\ud558\ub294 \uacf5\uc815\uac70\ub798\uc704\uc6d0\ud68c\uac00 \uc99d\uba85\ud558\uc5ec\uc57c \ud55c\ub2e4","\ud569\uc758\uac00 \uc788\uc5c8\ub354\ub77c\ub3c4 \uc2e4\ud589\ud589\uc704\ub85c \ub098\uc544\uac00\uc9c0 \uc54a\uc558\ub2e4\uba74 \ubd80\ub2f9\ud55c \uacf5\ub3d9\ud589\uc704\ub294 \uc131\ub9bd\ud558\uc9c0 \uc54a\ub294\ub2e4","\uc77c\uc815\ud55c \uac70\ub798\ubd84\uc57c\uc5d0\uc11c \uacbd\uc7c1\uc744 \uc2e4\uc9c8\uc801\uc73c\ub85c \uc81c\ud55c\ud558\uc5ec\uc57c \ud55c\ub2e4"],t.s)
